code.C:
#include <stdio.h>
int main(){
    printf("Structure: each member has its own memory location; size is sum of members (with padding).\n");
    printf("Union: all members share the same memory location; size is size of largest member.\n");
    printf("Access: structure members can be used simultaneously; union members cannot be used simultaneously.\n");
    return 0;
}

